// Read the TRACK_CREATORS env var and split into individual creator objects
const raw = $env.TRACK_CREATORS || '';
if (!raw.trim()) {
  throw new Error('TRACK_CREATORS env var is empty. Add comma-separated TikTok usernames.');
}

const usernames = raw
  .split(',')
  .map(u => u.trim().replace(/^@/, ''))
  .filter(Boolean);

return usernames.map(username => ({
  json: { username }
}));

// ─── Gather inputs from previous nodes ──────────────────────────────────────
const username     = $('For Each Creator').item.json.username;
const userResponse = $('TikTok User Info').item.json;
const postsResponse = $('TikTok Recent Videos').item.json;

// ─── Parse user profile ──────────────────────────────────────────────────────
const userInfo = userResponse?.data?.user?.stats
             || userResponse?.userInfo?.stats
             || userResponse?.stats
             || {};
const followerCount = Number(userInfo.followerCount || userInfo.fans || 0);

// ─── Parse posts ─────────────────────────────────────────────────────────────
const rawPosts = postsResponse?.data?.videos
              || postsResponse?.itemList
              || postsResponse?.data?.itemList
              || [];

if (rawPosts.length === 0) {
  return [{ json: {
    creatorName:        username,
    platform:           'TikTok',
    avgEngagementRate:  0,
    topContentThemes:   'No data',
    postingFrequency:   'Unknown',
    followerCount:      followerCount,
    lastAnalyzed:       new Date().toISOString(),
    bestPerformingHooks: 'No data',
  }}];
}

// ─── Compute engagement rates ─────────────────────────────────────────────────
const engagements = rawPosts.map(post => {
  const stats   = post.stats || post.statistics || {};
  const plays   = Number(stats.playCount   || stats.play_count   || 1);
  const likes   = Number(stats.diggCount   || stats.like_count   || 0);
  const comments= Number(stats.commentCount|| stats.comment_count|| 0);
  const shares  = Number(stats.shareCount  || stats.share_count  || 0);
  const rate    = plays > 0 ? ((likes + comments + shares) / plays) * 100 : 0;
  return { plays, likes, comments, shares, rate, post };
});

const avgEngRate = engagements.reduce((s, e) => s + e.rate, 0) / engagements.length;

// ─── Find top performer (for hooks) ──────────────────────────────────────────
const sorted = [...engagements].sort((a, b) => b.rate - a.rate);
const topHooks = sorted.slice(0, 3).map(e => {
  const desc = e.post.desc || e.post.description || e.post.video?.desc || '';
  return desc.split(/\s+/).slice(0, 10).join(' ');
}).filter(Boolean);

// ─── Extract content themes from hashtags ────────────────────────────────────
const allTags = [];
for (const { post } of engagements) {
  const challenges = post.challenges || post.textExtra || [];
  for (const ch of challenges) {
    const tag = ch.title || ch.hashtagName || ch.text || '';
    if (tag) allTags.push(tag.toLowerCase());
  }
  // also parse hashtags from description
  const desc = post.desc || post.description || '';
  const hashMatches = desc.match(/#[\w]+/g) || [];
  allTags.push(...hashMatches.map(t => t.replace('#', '').toLowerCase()));
}
// Count frequency
const tagFreq = {};
for (const t of allTags) { tagFreq[t] = (tagFreq[t] || 0) + 1; }
const topThemes = Object.entries(tagFreq)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([tag]) => `#${tag}`)
  .join(', ');

// ─── Posting frequency ───────────────────────────────────────────────────────
const timestamps = rawPosts
  .map(p => Number(p.createTime || p.create_time || 0))
  .filter(t => t > 0)
  .sort((a, b) => b - a);

let postingFrequency = 'Unknown';
if (timestamps.length >= 2) {
  const daysBetween = [];
  for (let i = 0; i < timestamps.length - 1; i++) {
    daysBetween.push((timestamps[i] - timestamps[i + 1]) / 86400);
  }
  const avgDays = daysBetween.reduce((s, d) => s + d, 0) / daysBetween.length;
  postingFrequency = `Every ${avgDays.toFixed(1)} days`;
}

return [{
  json: {
    creatorName:         username,
    platform:            'TikTok',
    avgEngagementRate:   Math.round(avgEngRate * 100) / 100,
    topContentThemes:    topThemes || 'No hashtags found',
    postingFrequency:    postingFrequency,
    followerCount:       followerCount,
    lastAnalyzed:        new Date().toISOString(),
    bestPerformingHooks: topHooks.join(' | ') || 'No hooks extracted',
  }
}];
